198	                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
199	                                !visited[nr][nc] && board[nr][nc] == current_flavor) {
200	                                visited[nr][nc] = true;
201	                                q_arr[tail++] = {nr, nc}; 
202	                            }
203	                        }
204	                    }
205	                    total_sq_sum += current_comp_size * current_comp_size;
206	                }
207	            }
208	        }
209	        return total_sq_sum;
