294	
295	        long long sum_sq_comp = calculate_sum_sq_comp_size();
296	        double dist_penalty_com = calculate_distance_penalty_CoM();
297	        double region_penalty_val = calculate_region_penalty();
298	        double edge_bonus_val = calculate_edge_bonus();
299	        
300	        double current_turn_double = static_cast<double>(turn_num_1_indexed);
301	        
302	        // Coefficients from Iteration 2 (best scoring), with small tweak to C
303	        double A_coeff_conn = 15.0 + 1.1 * current_turn_double; 
304	        double B_coeff_com_base = std::max(0.0, 170.0 - 1.7 * current_turn_double); 
305	        // Final iteration tweak for C_coeff_region_penalty_direct:
306	        double C_coeff_region_penalty_direct = std::max(2.0, 27.0 - 0.17 * current_turn_double); 
307	        double D_coeff_edge_bonus = 5.0 + 0.2 * current_turn_double; 
308	                
309	        return A_coeff_conn * sum_sq_comp 
310	             - B_coeff_com_base * dist_penalty_com 
311	             - C_coeff_region_penalty_direct * region_penalty_val
312	             + D_coeff_edge_bonus * edge_bonus_val;
313	    }
