// Monte Carlo rollout: simulate K future steps with greedy policy, return score
double mc_rollout(const Board& start_board, int current_turn_0idx, int rollout_depth, XorshiftRNG& local_rng) {
    Board board = start_board;
    int turn = current_turn_0idx;

    for (int step = 0; step < rollout_depth && turn < NUM_TURNS; ++step) {
        // Random placement for next candy
        int num_empty = board.count_empty();
        if (num_empty == 0) break;

        int p = local_rng.uniform_int(1, num_empty);
        auto [r, c] = board.find_pth_empty(p);
        board.place_candy(r, c, G_FLAVOR_SEQUENCE[turn]);
        turn++;

        // Greedy tilt: pick direction maximizing adjacencies
        int best_dir = board.greedy_best_dir();
        board.apply_tilt(best_dir);
    }

    return (double)board.compute_score();
}

// Decide tilt direction using Monte Carlo rollouts
int decide_direction_mc(const Board& board_after_placement, int current_turn_0idx) {
    // Adaptive parameters based on game phase
    int turns_remaining = NUM_TURNS - current_turn_0idx;

    // Rollout depth: look further ahead in early game, less in late game
    int rollout_depth;
    int num_rollouts;

    if (turns_remaining > 70) {
        rollout_depth = 12;
        num_rollouts = 8;
    } else if (turns_remaining > 40) {
        rollout_depth = 15;
        num_rollouts = 10;
    } else if (turns_remaining > 15) {
        rollout_depth = turns_remaining;
        num_rollouts = 12;
    } else {
        rollout_depth = turns_remaining;
        num_rollouts = 16;
    }

    double best_score = -1e18;
    int best_dir = 0;

    for (int d = 0; d < NUM_DIRECTIONS; ++d) {
        Board after_tilt = board_after_placement;
        after_tilt.apply_tilt(d);

        double total_score = 0.0;
        for (int r = 0; r < num_rollouts; ++r) {
            total_score += mc_rollout(after_tilt, current_turn_0idx, rollout_depth, rng);
        }
        double avg_score = total_score / num_rollouts;

        if (avg_score > best_score) {
            best_score = avg_score;
            best_dir = d;
        }
    }

    return best_dir;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    rng.seed(std::chrono::steady_clock::now().time_since_epoch().count());

    for (int t = 0; t < NUM_TURNS; ++t) {
        std::cin >> G_FLAVOR_SEQUENCE[t];
    }

    Board board;
    for (int t = 0; t < NUM_TURNS; ++t) {
        int p;
        std::cin >> p;

        auto [r, c] = board.find_pth_empty(p);
        board.place_candy(r, c, G_FLAVOR_SEQUENCE[t]);

        int dir = decide_direction_mc(board, t + 1);
        std::cout << DIR_CHARS[dir] << std::endl;
        board.apply_tilt(dir);
    }

    return 0;
}
